import { type DbClient, sessions, tryDb } from "@spectrum/db"
import type {
  HarnessId,
  ModelId,
  ProjectId,
  Session,
  SessionId,
} from "@spectrum/types"
import {
  type Clock,
  type IdGen,
  type Result,
  err,
  isErr,
  ok,
} from "@spectrum/utils"
import { type SQL, and, desc, eq, gte, isNotNull, isNull } from "drizzle-orm"
import type { SessionError } from "./errors"

export type { SessionError } from "./errors"

/** Fields the caller supplies; `id` and `startedAt` are generated by the store. */
export type SessionInput = {
  readonly harnessId: HarnessId
  readonly projectId: ProjectId
  readonly modelId?: ModelId
  readonly name?: string
  readonly cwd: string
}

/**
 * Optional, all-`AND` filter for `query`. `since` is an inclusive `startedAt >=` bound;
 * `running` selects open (`true`) or closed (`false`) sessions; `limit`/`offset` paginate
 * the `startedAt DESC` result.
 */
export type SessionFilter = {
  readonly harnessId?: HarnessId
  readonly modelId?: ModelId
  readonly projectId?: ProjectId
  readonly since?: string
  readonly running?: boolean
  readonly limit?: number
  readonly offset?: number
}

export interface SessionStore {
  create(input: SessionInput): Result<Session, SessionError>
  close(id: SessionId, exitCode: number): Result<Session, SessionError>
  /** Update an existing session's name. Returns the updated row, or not-found / invalid-name. */
  updateName(id: SessionId, name: string): Result<Session, SessionError>
  /** Persist the harness-native session id so the session can be resumed later. Idempotent. */
  setResumeId(id: SessionId, resumeId: string): Result<Session, SessionError>
  /** Clear endedAt/exitCode so an ended session is live again (the inverse of close). */
  reopen(id: SessionId): Result<Session, SessionError>
  /** Read a single session row, or undefined if not found. */
  get(id: SessionId): Result<Session | undefined, SessionError>
  /**
   * Read a single session by id and return the underlying DB row (retains all columns, including
   * `projectId`, which the public `Session` type drops). Returns `undefined` if not found.
   * Use this for cross-domain lookups (e.g. resolving a session's project from the GUI).
   */
  findById(id: SessionId): Result<SessionRow | undefined, SessionError>
  query(filter?: SessionFilter): Result<readonly Session[], SessionError>
  /**
   * Mark every session with `endedAt IS NULL` as ended using the injected clock timestamp.
   * `exitCode` is left NULL — the app was killed and the true exit code is unknown.
   * Returns `ok(count)` of orphaned sessions reconciled. Safe with no orphans; idempotent.
   */
  reconcileOrphaned(): Result<number, SessionError>
}

type SessionRow = typeof sessions.$inferSelect

/** Map a drizzle row into a Session, dropping NULL modelId/endedAt/exitCode/resumeId/name/cwd. */
const toSession = (row: SessionRow): Session => ({
  id: row.id as SessionId,
  harnessId: row.harnessId as HarnessId,
  startedAt: row.startedAt,
  ...(row.modelId !== null ? { modelId: row.modelId as ModelId } : {}),
  ...(row.endedAt !== null ? { endedAt: row.endedAt } : {}),
  ...(row.exitCode !== null ? { exitCode: row.exitCode } : {}),
  ...(row.resumeId !== null ? { resumeId: row.resumeId } : {}),
  ...(row.name !== null ? { name: row.name } : {}),
  ...(row.cwd !== null ? { cwd: row.cwd } : {}),
})

/** Convert a DbError boundary failure into the store's SessionError. */
const asSessionError = <T>(
  r: Result<T, { readonly detail: string }>,
): Result<T, SessionError> =>
  isErr(r) ? err({ kind: "db-failed", detail: r.error.detail }) : r

const buildConditions = (filter: SessionFilter): SQL[] => {
  const conditions: SQL[] = []
  if (filter.harnessId !== undefined)
    conditions.push(eq(sessions.harnessId, filter.harnessId))
  if (filter.modelId !== undefined)
    conditions.push(eq(sessions.modelId, filter.modelId))
  if (filter.projectId !== undefined)
    conditions.push(eq(sessions.projectId, filter.projectId))
  if (filter.since !== undefined)
    conditions.push(gte(sessions.startedAt, filter.since))
  if (filter.running === true) conditions.push(isNull(sessions.endedAt))
  else if (filter.running === false)
    conditions.push(isNotNull(sessions.endedAt))
  return conditions
}

export const createSessionStore = (deps: {
  readonly db: DbClient
  readonly clock: Clock
  readonly idGen: IdGen
}): SessionStore => {
  const { handle } = deps.db

  return {
    create: (input: SessionInput): Result<Session, SessionError> => {
      const id = deps.idGen.next("s") as SessionId
      const startedAt = deps.clock.now().toISOString()
      const written = asSessionError(
        tryDb(() =>
          handle
            .insert(sessions)
            .values({
              id,
              harnessId: input.harnessId,
              projectId: input.projectId,
              modelId: input.modelId ?? null,
              startedAt,
              name: input.name ?? null,
              cwd: input.cwd,
            })
            .run(),
        ),
      )
      if (isErr(written)) return written
      return ok({
        id,
        harnessId: input.harnessId,
        startedAt,
        ...(input.modelId !== undefined ? { modelId: input.modelId } : {}),
        ...(input.name !== undefined ? { name: input.name } : {}),
        cwd: input.cwd,
      })
    },

    close: (id: SessionId, exitCode: number): Result<Session, SessionError> => {
      const endedAt = deps.clock.now().toISOString()
      const written = asSessionError(
        tryDb(() =>
          handle
            .update(sessions)
            .set({ endedAt, exitCode })
            .where(eq(sessions.id, id))
            .run(),
        ),
      )
      if (isErr(written)) return written
      const fetched = asSessionError(
        tryDb(() =>
          handle.select().from(sessions).where(eq(sessions.id, id)).get(),
        ),
      )
      if (isErr(fetched)) return fetched
      if (fetched.value === undefined) return err({ kind: "not-found" })
      return ok(toSession(fetched.value))
    },

    updateName: (
      id: SessionId,
      name: string,
    ): Result<Session, SessionError> => {
      const trimmed = name.trim()
      if (trimmed === "") return err({ kind: "invalid-name" })
      const written = asSessionError(
        tryDb(() =>
          handle
            .update(sessions)
            .set({ name: trimmed })
            .where(eq(sessions.id, id))
            .run(),
        ),
      )
      if (isErr(written)) return written
      const fetched = asSessionError(
        tryDb(() =>
          handle.select().from(sessions).where(eq(sessions.id, id)).get(),
        ),
      )
      if (isErr(fetched)) return fetched
      if (fetched.value === undefined) return err({ kind: "not-found" })
      return ok(toSession(fetched.value))
    },

    setResumeId: (
      id: SessionId,
      resumeId: string,
    ): Result<Session, SessionError> => {
      const written = asSessionError(
        tryDb(() =>
          handle
            .update(sessions)
            .set({ resumeId })
            .where(eq(sessions.id, id))
            .run(),
        ),
      )
      if (isErr(written)) return written
      const fetched = asSessionError(
        tryDb(() =>
          handle.select().from(sessions).where(eq(sessions.id, id)).get(),
        ),
      )
      if (isErr(fetched)) return fetched
      if (fetched.value === undefined) return err({ kind: "not-found" })
      return ok(toSession(fetched.value))
    },

    reopen: (id: SessionId): Result<Session, SessionError> => {
      const written = asSessionError(
        tryDb(() =>
          handle
            .update(sessions)
            .set({ endedAt: null, exitCode: null })
            .where(eq(sessions.id, id))
            .run(),
        ),
      )
      if (isErr(written)) return written
      const fetched = asSessionError(
        tryDb(() =>
          handle.select().from(sessions).where(eq(sessions.id, id)).get(),
        ),
      )
      if (isErr(fetched)) return fetched
      if (fetched.value === undefined) return err({ kind: "not-found" })
      return ok(toSession(fetched.value))
    },

    get: (id: SessionId): Result<Session | undefined, SessionError> => {
      const fetched = asSessionError(
        tryDb(() =>
          handle.select().from(sessions).where(eq(sessions.id, id)).get(),
        ),
      )
      if (isErr(fetched)) return fetched
      return ok(
        fetched.value === undefined ? undefined : toSession(fetched.value),
      )
    },

    findById: (id: SessionId): Result<SessionRow | undefined, SessionError> => {
      const fetched = asSessionError(
        tryDb(() =>
          handle.select().from(sessions).where(eq(sessions.id, id)).get(),
        ),
      )
      if (isErr(fetched)) return fetched
      return ok(fetched.value)
    },

    reconcileOrphaned: (): Result<number, SessionError> => {
      const orphans = asSessionError(
        tryDb(() =>
          handle
            .select({ id: sessions.id })
            .from(sessions)
            .where(isNull(sessions.endedAt))
            .all(),
        ),
      )
      if (isErr(orphans)) return orphans
      const orphanCount = orphans.value.length
      if (orphanCount === 0) return ok(0)
      const endedAt = deps.clock.now().toISOString()
      const updated = asSessionError(
        tryDb(() =>
          handle
            .update(sessions)
            .set({ endedAt })
            .where(isNull(sessions.endedAt))
            .run(),
        ),
      )
      if (isErr(updated)) return updated
      return ok(orphanCount)
    },

    query: (
      filter?: SessionFilter,
    ): Result<readonly Session[], SessionError> => {
      const active = filter ?? {}
      const conditions = buildConditions(active)
      const rows = asSessionError(
        tryDb(() => {
          let q = handle.select().from(sessions).$dynamic()
          if (conditions.length > 0) q = q.where(and(...conditions))
          q = q.orderBy(desc(sessions.startedAt))
          // SQLite requires a LIMIT before OFFSET. drizzle only emits `limit` for
          // values >= 0, so a sentinel (effectively unbounded) limit stands in for
          // "no limit" when an offset is requested on its own.
          if (active.limit !== undefined) q = q.limit(active.limit)
          else if (active.offset !== undefined)
            q = q.limit(Number.MAX_SAFE_INTEGER)
          if (active.offset !== undefined) q = q.offset(active.offset)
          return q.all()
        }),
      )
      if (isErr(rows)) return rows
      return ok(rows.value.map(toSession))
    },
  }
}
